function solve(s: string): string[] {
    const segments: string[] = [];
    const seen = new Set<string>();
    let current = '';
    let i = 0;
    while (i < s.length) {
        current += s[i];
        if (!seen.has(current)) {
            seen.add(current);
            segments.push(current);
            current = '';
            i++;
        } else {
            i++;
        }
    }
    return segments;
}
